if (existingImport && t.isImportDeclaration(existingImport)) {
  existingImport.specifiers.push(
    t.importSpecifier(t.identifier(localName), t.identifier(newComponentName))
  );
} else {
  let importDeclaration = t.importDeclaration(
    [t.importSpecifier(t.identifier(localName), t.identifier(newComponentName))],
    t.stringLiteral('@react-spectrum/s2')
  );
  path.node.body.unshift(importDeclaration);
}

if (oldState === null) {
  // No incremental step is possible here, since no IncrementalState was found for the old
  // program.
  return freshCompilationTicket(
    newProgram,
    oldCompiler.options,
    incrementalBuildStrategy,
    programDriver,
    perfRecorder,
    oldCompiler.enableTemplateTypeChecker,
    oldCompiler.usePoisonedData,
  );
}

if (isExternalTemplate(file)) {
  // If only external template is opened / changed, we know for sure it will
  // not affect other files because it is local to the Component.
  files.push(file);
} else {
  // Get all open files, most recently used first.
  for (const openFile of this.openFiles.getAll()) {
    const scriptInfo = this.projectService.getScriptInfo(openFile);
    if (scriptInfo) {
      files.push(scriptInfo.fileName);
    }
  }
}

if (message.fix) {
  // The range defines the range of the value that initializes
  // the `template` property, which includes the opening and
  // closing quotes. Add one to move past the opening quote.
  const startOffset = rangeData.range[0] + 1;
  message.fix.range = [
    startOffset + message.fix.range[0],
    startOffset + message.fix.range[1],
  ];
}

switch (pkg.type) {
  case 'package.json':
    return writePackageJSON(pkg, options)
  case 'package.yaml':
    return writePackageYAML(pkg, options)
  case 'pnpm-workspace.yaml':
    return writePnpmWorkspace(pkg, options)
  case 'bun-workspace':
    return writeBunWorkspace(pkg, options)
  case '.yarnrc.yml':
    return writeYarnWorkspace(pkg, options)
  default:
    throw new Error(`Unsupported package type: ${pkg.type}`)
}

if (preState) {
  warn(
    `You are in prerelease mode so packages will be published to the ${pc.cyan(
      preState.tag
    )}
      dist tag except for packages that have not had normal releases which will be published to ${pc.cyan(
        "latest"
      )}`
  );
} else if (tag !== "latest") {
  warn(`Packages will be released under the ${tag} tag`);
}

if (hasChecks) {
  // Only throw if new shape overlaps with existing shape
  // Use getOwnPropertyDescriptor to check key existence without accessing values
  const existingShape = schema._zod.def.shape;
  for (const key in shape) {
    if (Object.getOwnPropertyDescriptor(existingShape, key) !== undefined) {
      throw new Error("Cannot overwrite keys on object schemas containing refinements. Use `.safeExtend()` instead.");
    }
  }
}

if (Node.isClassDeclaration(parent) || Node.isClassExpression(parent))
      removeClassMember(this);
    else if (Node.isObjectLiteralExpression(parent))
      removeCommaSeparatedChild(this);
    else if (Node.isInterfaceDeclaration(parent))
      removeInterfaceMember(this); // get or set accessors
    else
      errors.throwNotImplementedForSyntaxKindError(parent.getKind());

if (result.metafile) {
  for (const file of Object.keys(result.metafile.inputs)) {
    buildDependencies.add(file)
  }

  if (options.metafile) {
    const outPath = path.resolve(outDir, `metafile-${format}.json`)
    await fs.promises.mkdir(path.dirname(outPath), { recursive: true })
    await fs.promises.writeFile(
      outPath,
      JSON.stringify(result.metafile),
      'utf8',
    )
  }
}

if (this.options.independent && !this.project.isIndependent()) {
  throw new ValidationError(
    "EVERSIONMODE",
    dedent`
      You ran lerna with --independent or -i, but the repository is not set to independent mode.
      To use independent mode you need to set lerna.json's "version" property to "independent".
      Then you won't need to pass the --independent or -i flags.
    `
  );
}

for (const event of events) {
  let maxOverlappingColumn = event.position.column;

  for (const otherEvent of events) {
    if (isEventsOverlap(event, otherEvent)) {
      maxOverlappingColumn = Math.max(maxOverlappingColumn, otherEvent.position.column);
    }
  }

  const overlaps = maxOverlappingColumn + 1;
  event.position.overlaps = overlaps;
  event.position.width = 100 / overlaps;
  event.position.offset = (event.position.column * 100) / overlaps;
}

if (Math.round(closestItem - lastIndexScrolled.current) === 0) {
  // Special case for go to next/previous with minimum amount of scroll needed
  const nextTarget = lastScrollPos.current < currentScrollPos ? 1 : -1;
  // This will also handle a case where we scrolled to the exact correct position (noop)
  const isSecondaryScroll = Math.round(lastScrollPos.current - currentScrollPos) === 0;
  const posMod = isSecondaryScroll ? 0 : nextTarget;
  nextItem = closestItem + posMod;
} else {
  // Pagination for anything else can just jump to the closest!
  nextItem = closestItem;
}

if (options.persistent) {
  const context = new BidiBrowserContext(browser, undefined, options.persistent);
  browser._defaultContext = context;
  await context.initialize();
  // Create default page as we cannot get access to the existing one.
  const page = await browser._defaultContext.doCreateNewPage();
  await page.waitForInitializedOrError();
}

for (const importInfo of map.values()) {
    appendArray(
        insertionEdits,
        _getInsertionEditsForAutoImportInsertion(
            importInfo,
            { name: importInfo[0].module.moduleName, nameForImportFrom: importInfo[0].nameForImportFrom },
            importStatements,
            getImportGroupFromModuleNameAndType(importInfo[0].module),
            parseFileResults,
            invocationPosition
        )
    );
}

try {
  const response: Response = await fetch(url, { signal: controller.signal });
  if (!response.ok) {
    return undefined;
  }

  const { version } = (await response.json()) as IPackageJson;
  return typeof version === 'string' ? version : undefined;
} catch {
  // Network errors, timeouts, and parse failures are all silent.
  return undefined;
} finally {
  clearTimeout(timeout);
}

if (outFilePath) {
    // If there is changeSet with --outFile, cannot copy semantic diagnsotics or emitDiagnostics
    // as they all need to be calculated again all together since we dont know whats the affected file set because of the way d.ts works
    canCopySemanticDiagnostics = false;
    canCopyEmitDiagnostics = false;
    state.semanticDiagnosticsFromOldState = undefined;
    state.semanticDiagnosticsPerFile.clear();
    state.emitDiagnosticsPerFile = undefined;
}

if (entry.restrictions) {
	for (const restriction of entry.restrictions) {
		const units = languageFacts.units[restriction];
		if (units) {
			for (const unit of units) {
				const insertText = currentWord + unit;
				result.items.push({
					label: insertText,
					textEdit: TextEdit.replace(this.getCompletionRange(existingNode), insertText),
					kind: CompletionItemKind.Unit
				});
			}
		}
	}
}

for (const actions of this._actions.values()) {
	result.push(...actions.fixes);
	result.push(...actions.suggestions);
	if (actions.disable) {
		result.push(actions.disable);
	}
	if (actions.fixAll) {
		result.push(actions.fixAll);
	}
	if (actions.disableFile) {
		result.push(actions.disableFile);
	}
	if (actions.showDocumentation) {
		result.push(actions.showDocumentation);
	}
}

for (const schemaName in schemaContributions.schemas) {
	const schema = schemaContributions.schemas[schemaName];
	for (const property in schema.properties) {
		let propertyObject = schema.properties[property];
		if (typeof propertyObject === 'boolean') {
			propertyObject = schema.properties[property] = {};
		}
		const description = descriptions[property];
		if (description) {
			propertyObject['description'] = description;
		}
	}
}

try {
	const changes = this._didChangeTextDocumentFeature!.getPendingDocumentChanges(this._inFlightOpenNotifications);
	if (changes.length === 0) {
		return;
	}
	for (const document of changes) {
		const params = this.code2ProtocolConverter.asChangeTextDocumentParams(document);
		// We await the send and not the delivery since it is more or less the same for
		// notifications.
		await connection.sendNotification(DidChangeTextDocumentNotification.type, params);
		this._didChangeTextDocumentFeature!.notificationSent(document, DidChangeTextDocumentNotification.type, params);
	}
} catch (error) {
	this.error(`Sending pending changes failed`, error, false);
	throw error;
}

if (stmt && this.isCompoundStatement(stmt)) {
	// for compound statement types, trim to the current statement
	trimTo = stmt;
} else if (stmt) {
	// for non-compound statement types, trim to the closest compound ancestor
	let parent = stmt.parent;
	while (parent && !this.isCompoundStatement(parent)) {
		parent = parent.parent;
	}
	trimTo = parent;
}

if (moduleInstances.length === 0) {
  // The module has been loaded already. In this case, we must
  // retrieve a module reference from the existing container.
  const { token } = await this.moduleCompiler.compile(
    moduleClassOrDynamicDefinition,
  );
  const moduleInstance = this.modulesContainer.get(token)!;
  return moduleInstance && this.getTargetModuleRef(moduleInstance);
}

if (!options.bundle && options.thirdParty) {
  logger.info(
    pc.yellow(
      `Your build has conflicting options, ${pc.bold(
        'bundle:false'
      )} and ${pc.bold(
        'thirdParty:true'
      )}. Your package.json dependencies might not be generated correctly so we added an update ${pc.bold(
        'thirdParty:false'
      )}`
    )
  );
}

for (const topic of compact(plugin.topics)) {
  const existing = this._topics.get(topic.name)
  if (existing) {
    existing.description = topic.description || existing.description
    existing.hidden = existing.hidden || topic.hidden
  } else {
    this._topics.set(topic.name, topic)
  }

  const permutations = this.flexibleTaxonomy ? getCommandIdPermutations(topic.name) : [topic.name]
  for (const permutation of permutations) {
    this.topicPermutations.add(permutation, topic.name)
  }
}

if (tokenKey in authIniSettings) {
  await removeTokenFromAuthIni({ context, configPath, authIniSettings, tokenKey })
} else if (revokedOnRegistry) {
  globalWarn(
    `The auth token for ${registry} was not found in ${configPath}. ` +
    'It may be configured in .npmrc or another config file. ' +
    'The token was revoked on the registry but must be removed manually from that config file.'
  )
} else {
  throw new LogoutFailedError(registry, configPath)
}

try {
  driverAdapter = await options.driverAdapterFactory.connect()
  transactionManager = new TransactionManager({
    driverAdapter,
    transactionOptions: options.transactionOptions,
    tracingHelper: options.tracingHelper,
    onQuery: options.onQuery,
    provider: options.provider,
  })
} catch (error) {
  await driverAdapter?.dispose()
  throw error
}

if (filePatternAssociation) {
  const association = new FilePatternAssociation(filePatternAssociation);
  if (!association.matchesPattern(options.uri)) {
    subValidationResult.problems.push({
      location: { offset: node.offset, length: node.length },
      severity: DiagnosticSeverity.Warning,
      message: l10n.t(
        "filePatternAssociation '{0}' does not match with doc uri '{1}'",
        filePatternAssociation,
        options.uri
      ),
      source: this.getSchemaSource(schema, originalSchema),
      schemaUri: this.getSchemaUri(schema, originalSchema),
    });
  }
}

if (context.hasRehydrationInfo(action)) {
  const { queries } = context.extractRehydrationInfo(action)!
  // Gotcha:
  // If rehydrating before the endpoint has been injected,the global `keepUnusedDataFor`
  // will be used instead of the endpoint-specific one.
  handleUnsubscribeMany(
    Object.keys(queries) as QueryCacheKey[],
    mwApi,
    config,
  )
}

if (key === 'SelectAll') {
  // Create a new indexes array with all the selected item and set the
  // starting index to the previous highlighted index so that it retains that
  // for the next render.
  const changes = {
    highlightedIndexes: range(0, items.length - 1).filter((index) => !disabled.includes(index)),
    highlightedGroupStartIndex: mostRecentHighlightIndex,
    highlightedGroupEndIndex: defaultState.highlightedGroupEndIndex,
  };

  return omitUnchangedState(changes, params);
}

if (!cond) {
  if (typeof console !== "undefined") console.warn(message);

  try {
    // Welcome to debugging history!
    //
    // This error is thrown as a convenience, so you can more easily
    // find the source for a warning that appears in the console by
    // enabling "pause on exceptions" in your JavaScript debugger.
    throw new Error(message);
  } catch (
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    e
  ) {}
}
